// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title TrustVote
 * @notice Multi-election voting contract with hybrid voter registration.
 * @dev Supports multiple concurrent elections. Each election has its own
 *      set of candidates and independent voter tracking.
 *
 *      Key design decisions:
 *      - Owner can create elections and add candidates
 *      - Any registered voter can vote once per election
 *      - Results are publicly readable at any time
 *      - Events emitted for all state changes (frontend indexing)
 */
contract TrustVote is Ownable {

    // ======================== Structs ========================

    struct Candidate {
        uint256 id;
        string name;
        uint256 voteCount;
    }

    struct Election {
        uint256 id;
        string name;
        uint256 candidateCount;
        uint256 startTime;
        uint256 endTime;
        bool exists;
    }

    // ======================== State ========================

    /// @notice Total number of elections created
    uint256 public electionCount;

    /// @notice Mapping from election ID to Election struct
    mapping(uint256 => Election) public elections;

    /// @notice Mapping from election ID => candidate ID => Candidate struct
    mapping(uint256 => mapping(uint256 => Candidate)) public candidates;

    /// @notice Tracks whether a voter has voted in a given election
    /// election ID => voter address => bool
    mapping(uint256 => mapping(address => bool)) public hasVoted;

    /// @notice Registered voters (hybrid: also tracked off-chain in MongoDB)
    mapping(address => bool) public registeredVoters;

    // ======================== Events ========================

    event ElectionCreated(uint256 indexed electionId, string name, uint256 startTime, uint256 endTime);
    event CandidateAdded(uint256 indexed electionId, uint256 candidateId, string name);
    event VoteCast(uint256 indexed electionId, uint256 indexed candidateId, address indexed voter);
    event ElectionEnded(uint256 indexed electionId);
    event VoterRegistered(address indexed voter);

    // ======================== Modifiers ========================

    modifier electionExists(uint256 _electionId) {
        require(elections[_electionId].exists, "Election does not exist");
        _;
    }

    modifier electionActive(uint256 _electionId) {
        require(
            block.timestamp >= elections[_electionId].startTime,
            "Election has not started yet"
        );
        require(
            block.timestamp <= elections[_electionId].endTime,
            "Election has ended"
        );
        _;
    }

    modifier hasNotVoted(uint256 _electionId) {
        require(!hasVoted[_electionId][msg.sender], "You have already voted in this election");
        _;
    }

    modifier onlyRegistered() {
        require(registeredVoters[msg.sender], "You are not a registered voter");
        _;
    }

    // ======================== Constructor ========================

    constructor() Ownable(msg.sender) {}

    // ======================== Admin Functions ========================

    /**
     * @notice Register a voter address (hybrid: also tracked in MongoDB).
     * @param _voter The address to register.
     */
    function registerVoter(address _voter) external onlyOwner {
        require(_voter != address(0), "Invalid voter address");
        require(!registeredVoters[_voter], "Voter already registered");

        registeredVoters[_voter] = true;
        emit VoterRegistered(_voter);
    }

    /**
     * @notice Create a new election.
     * @param _name Name/title of the election.
     * @param _startTime Unix timestamp when voting opens.
     * @param _endTime Unix timestamp when voting closes.
     */
    function createElection(
        string calldata _name,
        uint256 _startTime,
        uint256 _endTime
    ) external onlyOwner {
        require(bytes(_name).length > 0, "Election name cannot be empty");
        require(_endTime > _startTime, "End time must be after start time");

        electionCount++;

        elections[electionCount] = Election({
            id: electionCount,
            name: _name,
            candidateCount: 0,
            startTime: _startTime,
            endTime: _endTime,
            exists: true
        });

        emit ElectionCreated(electionCount, _name, _startTime, _endTime);
    }

    /**
     * @notice Add a candidate to an election (before it starts).
     * @param _electionId The election to add the candidate to.
     * @param _name The candidate's name.
     */
    function addCandidate(
        uint256 _electionId,
        string calldata _name
    ) external onlyOwner electionExists(_electionId) {
        require(
            block.timestamp < elections[_electionId].startTime,
            "Cannot add candidates after election has started"
        );
        require(bytes(_name).length > 0, "Candidate name cannot be empty");

        elections[_electionId].candidateCount++;
        uint256 candidateId = elections[_electionId].candidateCount;

        candidates[_electionId][candidateId] = Candidate({
            id: candidateId,
            name: _name,
            voteCount: 0
        });

        emit CandidateAdded(_electionId, candidateId, _name);
    }

    // ======================== Voting ========================

    /**
     * @notice Cast a vote for a candidate in an active election.
     * @param _electionId The election to vote in.
     * @param _candidateId The candidate to vote for.
     */
    function vote(
        uint256 _electionId,
        uint256 _candidateId
    )
        external
        electionExists(_electionId)
        electionActive(_electionId)
        onlyRegistered
        hasNotVoted(_electionId)
    {
        require(
            _candidateId > 0 && _candidateId <= elections[_electionId].candidateCount,
            "Invalid candidate ID"
        );

        hasVoted[_electionId][msg.sender] = true;
        candidates[_electionId][_candidateId].voteCount++;

        emit VoteCast(_electionId, _candidateId, msg.sender);
    }

    // ======================== View Functions ========================

    /**
     * @notice Get election details.
     * @param _electionId The election to query.
     */
    function getElection(uint256 _electionId)
        external
        view
        electionExists(_electionId)
        returns (
            string memory name,
            uint256 candidateCount,
            uint256 startTime,
            uint256 endTime
        )
    {
        Election storage e = elections[_electionId];
        return (e.name, e.candidateCount, e.startTime, e.endTime);
    }

    /**
     * @notice Get a candidate's info and vote count.
     * @param _electionId The election the candidate belongs to.
     * @param _candidateId The candidate to query.
     */
    function getCandidate(uint256 _electionId, uint256 _candidateId)
        external
        view
        electionExists(_electionId)
        returns (string memory name, uint256 voteCount)
    {
        require(
            _candidateId > 0 && _candidateId <= elections[_electionId].candidateCount,
            "Invalid candidate ID"
        );
        Candidate storage c = candidates[_electionId][_candidateId];
        return (c.name, c.voteCount);
    }

    /**
     * @notice Get results for all candidates in an election.
     * @param _electionId The election to query results for.
     * @return names Array of candidate names.
     * @return voteCounts Array of vote counts (same index as names).
     */
    function getResults(uint256 _electionId)
        external
        view
        electionExists(_electionId)
        returns (string[] memory names, uint256[] memory voteCounts)
    {
        uint256 count = elections[_electionId].candidateCount;
        names = new string[](count);
        voteCounts = new uint256[](count);

        for (uint256 i = 1; i <= count; i++) {
            names[i - 1] = candidates[_electionId][i].name;
            voteCounts[i - 1] = candidates[_electionId][i].voteCount;
        }

        return (names, voteCounts);
    }
}

